// __WELCOME_GEN_CONFIG__  __END__
using System;
using UnityEditor;
using UnityEngine;
using UnityEngine.UIElements;

namespace UnityMCP.Editor.Welcome
{
    /// <summary>
    /// Self-contained welcome window (shell: header, tabs, footer). Its content
    /// is decoded at runtime from the base64 config embedded above; the studio
    /// "AnkleBreaker" tab + footer links are fixed across every generated asset.
    /// The two tabs and the shared building blocks live in sibling partials.
    /// Generated by the AnkleBreaker Welcome Generator -edit it from there.
    /// </summary>
    public sealed partial class UnityMcpWelcomeWindow : UnityEditor.EditorWindow
    {
        // Fixed studio links (identical for every generated asset).
        private const string STUDIO_URL = "https://www.anklebreaker-studio.com";
        private const string CONSULTING_URL = "https://www.anklebreaker-consulting.com";
        private const string DISCORD_URL = "https://discord.gg/jrgNeUn6Ft";
        private const string GITHUB_URL = "https://github.com/orgs/AnkleBreaker-Studio";
        private const string DEVLOG_URL = "https://anklebreaker-studio.com/devlog";
        private const string CAREERS_URL = "https://anklebreaker-studio.com/careers";
        private const string GAMES_URL = "https://anklebreaker-studio.com/#games";

        // The window's own config, embedded so it ships with zero data files.
        private const string CONFIG_B64 = "";

        private const string MENU_PATH = "Window/AB Unity MCP/Welcome";

        private UnityMcpWelcomeConfig _config;
        private ScrollView _scroll;
        private VisualElement _tabWelcome;
        private VisualElement _tabAnkle;
        private int _activeTab = -1;

        // priority 0 pins Welcome above the asset's other items in the same menu path.
        [MenuItem(MENU_PATH, false, 0)]
        public static void Open()
        {
            UnityMcpWelcomeWindow window = GetWindow<UnityMcpWelcomeWindow>(true, "AnkleBreaker Unity MCP", true);
            window.minSize = new Vector2(460, 560);
            window.maxSize = new Vector2(640, 860);
            Rect r = window.position;
            r.width = 520;
            r.height = 660;
            window.position = r;
            window.Show();
        }

        private static UnityMcpWelcomeConfig LoadConfig()
        {
            try
            {
                string json = System.Text.Encoding.UTF8.GetString(Convert.FromBase64String(CONFIG_B64));
                UnityMcpWelcomeConfig c = JsonUtility.FromJson<UnityMcpWelcomeConfig>(json);
                return c ?? new UnityMcpWelcomeConfig();
            }
            catch
            {
                return new UnityMcpWelcomeConfig();
            }
        }

        private void CreateGUI()
        {
            _config = LoadConfig();
            UnityMcpWelcomeTheme.Apply(rootVisualElement);
            BuildShell();
        }

        private void BuildShell()
        {
            if (_config == null) _config = LoadConfig();
            VisualElement root = rootVisualElement;
            root.Clear();
            root.style.paddingLeft = 12;
            root.style.paddingRight = 12;
            root.style.paddingTop = 8;

            Label title = new Label(_config.ProductName);
            title.style.fontSize = 20;
            title.style.unityFontStyleAndWeight = FontStyle.Bold;
            title.style.unityTextAlign = TextAnchor.MiddleCenter;
            title.style.color = new Color(0.96f, 0.63f, 0.28f);
            title.style.whiteSpace = WhiteSpace.Normal;
            title.style.flexShrink = 0;
            root.Add(title);

            Label subtitle = new Label(_config.Subtitle);
            subtitle.style.unityTextAlign = TextAnchor.MiddleCenter;
            subtitle.style.color = new Color(0.92f, 0.88f, 0.84f, 0.6f);
            subtitle.style.fontSize = 11;
            subtitle.style.marginBottom = 14;
            subtitle.style.flexShrink = 0;
            root.Add(subtitle);

            VisualElement tabs = new VisualElement();
            tabs.AddToClassList("ab-navtabs");
            tabs.style.flexDirection = FlexDirection.Row;
            _tabWelcome = BuildTab("Welcome", () => SelectTab(0));
            _tabAnkle = BuildTab("AnkleBreaker", () => SelectTab(1));
            tabs.Add(_tabWelcome);
            tabs.Add(_tabAnkle);
            root.Add(tabs);

            _scroll = new ScrollView(ScrollViewMode.Vertical);
            _scroll.AddToClassList("ab-scroll");
            _scroll.style.minHeight = 0;
            _scroll.contentContainer.style.paddingTop = 8;
            _scroll.contentContainer.style.paddingBottom = 8;
            root.Add(_scroll);

            VisualElement sep = new VisualElement();
            sep.AddToClassList("ab-separator");
            sep.style.flexShrink = 0;
            root.Add(sep);
            root.Add(BuildLinksRow());
            root.Add(BuildBottomRow());

            _activeTab = -1;
            SelectTab(0);
        }

        private static VisualElement BuildTab(string text, Action clicked)
        {
            Label tab = new Label(text);
            tab.AddToClassList("ab-navtab");
            tab.style.flexGrow = 1;
            tab.style.flexBasis = 0;
            tab.AddManipulator(new Clickable(clicked));
            return tab;
        }

        private void SelectTab(int index)
        {
            if (_scroll == null || index == _activeTab) return;
            _activeTab = index;
            SetActive(_tabWelcome, index == 0);
            SetActive(_tabAnkle, index == 1);
            _scroll.Clear();
            _scroll.scrollOffset = Vector2.zero;
            if (index == 1) BuildStudioTab();
            else BuildWelcomeTab();
        }

        private static void SetActive(VisualElement tab, bool active)
        {
            if (active) tab.AddToClassList("ab-navtab--active");
            else tab.RemoveFromClassList("ab-navtab--active");
        }

        // --- Footer -----------------------------------------------------------

        private VisualElement BuildLinksRow()
        {
            VisualElement row = new VisualElement();
            row.style.flexDirection = FlexDirection.Row;
            row.style.flexShrink = 0;
            row.style.marginBottom = 6;
            row.Add(MakeLinkButton("Studio", STUDIO_URL));
            row.Add(MakeLinkButton("Consulting", CONSULTING_URL));
            row.Add(MakeLinkButton("Discord", DISCORD_URL));
            return row;
        }

        private VisualElement BuildBottomRow()
        {
            VisualElement row = new VisualElement();
            row.style.flexDirection = FlexDirection.Row;
            row.style.alignItems = Align.Center;
            row.style.flexShrink = 0;
            row.style.marginBottom = 4;

            Toggle dontShow = new Toggle("Don't show this again") { focusable = false, value = UnityMcpWelcomeAutoOpen.DontShowAgain };
            dontShow.RegisterValueChangedCallback(e => UnityMcpWelcomeAutoOpen.DontShowAgain = e.newValue);
            row.Add(dontShow);

            VisualElement spacer = new VisualElement();
            spacer.style.flexGrow = 1;
            row.Add(spacer);

            Button gotIt = new Button(Close) { text = "  Got it, let's go!  ", focusable = false };
            gotIt.AddToClassList("ab-accent-button");
            gotIt.style.minWidth = 0;
            row.Add(gotIt);
            return row;
        }
    }
}
